from typing import List, Optional, Iterable

from geosat.cloud import PointCloud
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.psanp.abstractions.stage import Stage
from geosat.tools.urlprotocol import UrlProtocols


def infer_output_path(
    directory: Optional[str], filename: Optional[str], fallback_path: str
) -> str:
    """Build an output path from a directory path and a filename

    :param directory: S3 or local path of a directory or None
    :param filename: name of the output file or None
    :param fallback_path: used if filename is not provided
    :return: a S3 or local path to the output file

    >>> infer_output_path(None, None, "folder/name.laz")
    'folder/name.laz'
    >>> infer_output_path(None, "filename.laz", "folder/name.laz")
    'filename.laz'
    >>> infer_output_path("s3://psanp", None, "folder/name.laz")
    's3://psanp/name.laz'
    >>> infer_output_path("s3://psanp", "filename.laz", "folder/name.laz")
    's3://psanp/filename.laz'
    >>> infer_output_path("s3://psanp", "$name_suffix.laz", "folder/my_cloud.laz")
    's3://psanp/my_cloud_suffix.laz'
    """
    protocol = UrlProtocols()
    input_cloud_path = protocol.extract_path(fallback_path)
    if directory is not None and filename is not None:
        output_path = protocol.integrate_path(
            directory, protocol.extract_path(filename)
        )
    elif directory is not None:
        output_path = protocol.integrate_path(directory, input_cloud_path)
    elif filename is not None:
        output_path = filename
    else:
        output_path = fallback_path
    return output_path.replace("$name", input_cloud_path.stem)


class NullWriter(Stage):
    """This writer does nothing"""

    @classmethod
    def options(cls) -> List[Option]:
        return []

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        return (cloud,)


class CloudSaver(Stage):
    """A stage that saves a point cloud to a LAS or LAZ file at a given location:
    on the disk or on AWS S3.

    This stage has two option, "directory" and "filename":
    The stage will understand where the cloud should be saved depending
    on which option is given or not.

    - If nothing is given, the input file will be overwritten,
    - If only the directory is given, the file will be saved there
      with the same name
    - If only the filename is given it will be considered as a path and save the file there.
    - If both directory and filename are given, the path will be the concatenation of
      both
    """

    def __init__(
        self,
        filename: Optional[str] = None,
        directory: Optional[str] = None,
        stage_name: Optional[str] = None,
    ):
        super().__init__(stage_name)
        self.filename = filename
        self.directory = directory

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "filename",
                "The name of the file to save, with a `.las` or `.laz` "
                "extension. It can contain occurrences of `$name`, that will be "
                "replaced by the input name of the point cloud.",
                type_cast=str,
                required=False,
            ),
            Option(
                "directory",
                "Directory where the file should be written",
                type_cast=str,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, _pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        output_path = infer_output_path(
            self.directory, self.filename, cloud.metadata["filepath"]
        )
        cloud.save(to_path=output_path)
        return (cloud,)
